, { useEffect, useState } from 'react';
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Container,
  Grid,
  Pagination,
  Paper,
  Stack,
  Typography,
} from '@mui/material';

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || '';

function FeedPage() {
  const [posts, setPosts] = useState([]);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchPosts = async (targetPage) => {
    setLoading(true);
    setError('');

    try {
      const response = await fetch(`${API_BASE_URL}/api/posts?page=${targetPage}&limit=10`);
      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to load feed.');
      }

      const data = await response.json();
      setPosts(data.posts || []);
      setPage(data.page || 1);
      setTotalPages(data.totalPages || 1);
    } catch (error) {
      setError(error.message || 'Network error: could not reach feed server.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPosts(page);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handlePageChange = (event, value) => {
    setPage(value);
    fetchPosts(value);
  };

  return (
    <Container maxWidth="md" sx={{ mt: 2 }}>
      <Paper elevation={3} sx={{ p: 3 }}>
        <Typography variant="h4" component="h1" gutterBottom>
          Global Feed
        </Typography>

        {error && <Alert severity="error">{error}</Alert>}

        {!error && !loading && posts.length === 0 && (
          <Typography sx={{ mt: 2 }}>No posts yet. Check back later.</Typography>
        )}

        {loading ? (
          <Typography sx={{ mt: 2 }}>Loading posts...</Typography>
        ) : (
          <Stack spacing={2} sx={{ mt: 2 }}>
            {posts.map((post) => (
              <Card key={post._id} variant="outlined">
                <CardContent>
                  <Typography variant="h6">{post.title}</Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                    by {post.authorName} (@{post.authorUsername}) on {new Date(post.createdAt).toLocaleString()}
                  </Typography>
                  <Typography variant="body1" sx={{ mt: 1 }}>
                    {post.body}
                  </Typography>
                </CardContent>
              </Card>
            ))}
          </Stack>
        )}

        <Box sx={{ display: 'flex', justifyContent: 'center', mt: 3 }}>
          <Pagination
            count={totalPages}
            page={page}
            onChange={handlePageChange}
            color="primary"
            siblingCount={0}
            boundaryCount={1}
          />
        </Box>

        <Grid container spacing={1} sx={{ mt: 1 }}>
          <Grid item>
            <Button
              variant="outlined"
              disabled={page <= 1 || loading}
              onClick={() => handlePageChange(null, page - 1)}
            >
              Previous
            </Button>
          </Grid>
          <Grid item>
            <Button
              variant="outlined"
              disabled={page >= totalPages || loading}
              onClick={() => handlePageChange(null, page + 1)}
            >
              Next
            </Button>
          </Grid>
        </Grid

